class Solution:
  def shortestPathLength(self, graph: List[List[int]]) -> int:
    n = len(graph)
    _______________
    goal = (1 << n) - 1

    ans = 0
    q = collections.deque()  
    seen = set()

    for i in range(n):
      q.append((i, 1 << i))

    while q:
      for _ in range(len(q)):
        u, state = q.popleft()
        if state == goal:
          return ans
        if (u, state) in seen:
          continue
        seen.add((u, state))
        for v in graph[u]:
          q.append((v, state | (1 << v)))
      ans += 1

    return -1

