import java.util.*;
public class Main {

  private static long X = 1000000007;

  public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int N = sc.nextInt();
    int M = sc.nextInt();
    int[][] graph = new int[N+1][N+1];
    for (int i = 0; i < M; i++) {
      int u = sc.nextInt();
      int v = sc.nextInt();
      graph[u][v] = 1;
    }
    int S = sc.nextInt();
    int T = sc.nextInt();

    Set<Integer> reachable = new HashSet<>();
    reachable.add(T);
    boolean hasNewNode = true;

    boolean reachStart = false;
    int count = 0;

    LinkedList<Integer> queue = new LinkedList<>();
    queue.add(T);
    while (hasNewNode && !reachStart) {

      check(graph, queue);
      count++;

      hasNewNode = false;
      Iterator<Integer> itr = queue.iterator();
      while(itr.hasNext()){
        int node = itr.next();
        if (node == S) {
          reachStart = true;
        }
        hasNewNode |= reachable.add(node);
      }
    }

    if (reachStart) {
      System.out.println(count);
    } else {
      System.out.println(-1);
    }
  }

  private static void check(int[][] graph, LinkedList<Integer> queue) {

    for (int c = 0; c < 3; c++) {
      int nodeCount = queue.size();
      while (nodeCount-- > 0) {
        Integer node = queue.remove();
        for (int i = 1; i < graph.length; i++) {
          int v = graph[i][node];
          if (v == 1) {
            queue.add(i);
          }
        }
      }
    }
  }
}

import java.util.*;
public class Main {
  public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int H = sc.nextInt();
    int W = sc.nextInt();

    char[][] A = new char[H][W];
    for (int i = 0; i < H; i++) {
      String line = sc.next();
      for (int j = 0; j < line.length(); j++) {
        A[i][j] = line.charAt(j);
      }
    }

    int ans = resolve(A);

    System.out.println(ans);
    //System.out.println(Arrays.deepToString(A));
  }

  // up, down, left, right
  private static final int[] dx = { 0, 0, -1, 1 };
  private static final int[] dy = { -1, 1, 0, 0 };

  private static int resolve(char[][] a) {

    Queue<Node> queue = new ArrayDeque<Node>();

    // initial scan
    for (int i = 0; i < a.length; i++) {
      for (int j = 0; j < a[i].length; j++) {
        if (a[i][j] == '#') {
          queue.add(new Node(j, i, 0));
        }
      }
    }

    int max = 0;
    while (!queue.isEmpty()) {
      Node node = queue.remove();
      for (int i = 0; i < 4; i++) {
        int x = node.x + dx[i];
        int y = node.y + dy[i];
        int distance = node.distance + 1;
        if (y < 0 || a.length <= y || x < 0 || a[y].length <= x) {
          continue;
        }
        if (a[y][x] == '.') {
          a[y][x] = '#';
          queue.add(new Node(x, y, distance));
          max = Math.max(max, distance);
        }

      }
    }

    return max;
  }

  static class Node {
    final int x;
    final int y;
    final int distance;
    Node(int x, int y, int distance) {
      this.x = x;
      this.y = y;
      this.distance = distance;
    }
  }
}

