			B.right = scanner.nextInt() + 1;

			SortedSet<Node> sub = nodeSet.subSet(A, B);

			if (!sub.isEmpty()) {

				for (Node node : sub){
					int cost = node.right - node.left;
					int num  = costMap.get(cost);
					if (num != 1) {
						costMap.put(cost, num - 1);
					} else {
						costMap.remove(cost);
					}
				}

				if (B.right != W+1) {
					Node node = sub.last();
					node.right = B.right;
					int cost = node.right - node.left;
					costMap.put(cost, costMap.getOrDefault(node,0)+1);
					nodeSet.add(node);
				}

				sub.clear();
			}
			if (costMap.isEmpty()) {
				System.out.println(-1);
			} else {
				System.out.println(costMap.firstKey() + h);
			}
		}
	}

	public static void main(String[] args) {
		new Main();
	}
}

class FastScanner {
	private final InputStream in = System.in;
	private final byte[] buffer = new byte[1024];
	private int ptr = 0;
	private int buflen = 0;

	private boolean hasNextByte() {
		if (ptr < buflen) {
			return true;
		} else {
			ptr = 0;
			try {
				buflen = in.read(buffer);
			} catch (IOException e) {
				e.printStackTrace();
			}
			if (buflen <= 0) {
				return false;
			}
		}
		return true;
	}

	private int readByte() {
		if (hasNextByte()) return buffer[ptr++];
		else return -1;
	}

	private static boolean isPrintableChar(int c) {
		return 33 <= c && c <= 126;
	}

	public boolean hasNext() {
		while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
		return hasNextByte();
	}

	public String next() {
		if (!hasNext()) throw new NoSuchElementException();
		StringBuilder sb = new StringBuilder();
		int b = readByte();
		while (isPrintableChar(b)) {
			sb.appendCodePoint(b);
			b = readByte();
		}
		return sb.toString();
	}

	public long nextLong() {
		if (!hasNext()) throw new NoSuchElementException();
		long n = 0;
		boolean minus = false;
		int b = readByte();
		if (b == '-') {
			minus = true;
			b = readByte();
		}
		if (b < '0' || '9' < b) {
			throw new NumberFormatException();
		}
		while (true) {
			if ('0' <= b && b <= '9') {
				n *= 10;
				n += b - '0';
			} else if (b == -1 || !isPrintableChar(b)) {
				return minus ? -n : n;
			} else {
				throw new NumberFormatException();
			}
			b = readByte();
		}
	}

	public int nextInt() {
		long nl = nextLong();
		if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
		return (int) nl;
	}

	public double nextDouble() {
		return Double.parseDouble(next());
	}
}

import java.util.*;
import java.io.*;
import java.nio.charset.StandardCharsets;

public class Main {
	static class Node {
		int id;
		List<Edge> edges = new ArrayList<>();
		/*
		 * Queue<Edge> edges = new PriorityQueue<>(new Comparator<Edge>() {
		 * 
		 * @Override public int compare(Edge o1, Edge o2) { return -1 *
		 * Integer.compare(o1.length, o2.length); } });
		 */
		Set<Edge> passedEdges = new HashSet<>();
		int dist = Integer.MIN_VALUE / 2;

		Node(int id) {
			this.id = id;
		}
	}

	static class Edge {
		int src, dst, length;

		Edge(int src, int dst, int length) {
			this.src = src;
			this.dst = dst;
			this.length = length;
		}
	}

	public static void main(String[] args) throws IOException {
		InputStreamReader reader = new InputStreamReader(System.in, StandardCharsets.UTF_8);
		BufferedReader in = new BufferedReader(reader);
		String[] tokens = in.readLine().split(" ");
		int N = Integer.parseInt(tokens[0]);
		int M = Integer.parseInt(tokens[1]);
		int P = Integer.parseInt(tokens[2]);

		Node[] graph = new Node[N];
		for (int i = 0; i < N; ++i) {
			graph[i] = new Node(i);
		}
		List<Edge> edges = new ArrayList<>(M);
		for (int i = 0; i < M; ++i) {
			tokens = in.readLine().split(" ");
			int a = Integer.parseInt(tokens[0]);
			int b = Integer.parseInt(tokens[1]);
			int c = Integer.parseInt(tokens[2]);
			Edge edge = new Edge(a - 1, b - 1, c - P);
			graph[a - 1].edges.add(edge);
			edges.add(edge);
		}
		// 開始ノードの距離は0
		graph[0].dist = 0;

		for (int i = 0; i < N; ++i) {
			for (int j = 0; j < edges.size(); ++j) {
				Edge edge = edges.get(j);
				if (graph[edge.dst].dist < graph[edge.src].dist + edge.length) {
					graph[edge.dst].dist = graph[edge.src].dist + edge.length;
					graph[edge.dst].passedEdges.addAll(graph[edge.src].passedEdges);
					graph[edge.dst].passedEdges.add(edge);
				}
			}
		}

		// 閉路チェック
		boolean hasNegativeLoop = false;
		for (Edge edge : graph[graph.length - 1].passedEdges) {
			if (graph[edge.src].dist + edge.length > graph[edge.dst].dist) {
				hasNegativeLoop = true;
				break;
			}
		}
		if (hasNegativeLoop) {
			System.out.println("-1");
		} else {
			int result = Math.max(0, graph[graph.length - 1].dist);
			System.out.println(result);
		}
	}
}

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.PriorityQueue;

public class Main {
	static int n, m, l;
	static List<List<Hen>> list;

	public static void main(String[] args) throws Exception {
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		String[] sa = br.readLine().split(" ");
		n = Integer.parseInt(sa[0]);
		m = Integer.parseInt(sa[1]);
		l = Integer.parseInt(sa[2]);
		list = new ArrayList<>(n);
		for (int i = 0; i < n; i++) {
			list.add(new ArrayList<>());
		}
		for (int i = 0; i < m; i++) {
			sa = br.readLine().split(" ");
			int a = Integer.parseInt(sa[0]) - 1;
			int b = Integer.parseInt(sa[1]) - 1;
			int c = Integer.parseInt(sa[2]);
			if (c <= l) {
				list.get(a).add(new Hen(b, c));
				list.get(b).add(new Hen(a, c));
			}
		}
		int q = Integer.parseInt(br.readLine());
		int[] s = new int[q];
		int[] t = new int[q];
		for (int i = 0; i < q; i++) {
			sa = br.readLine().split(" ");
			s[i] = Integer.parseInt(sa[0]) - 1;
			t[i] = Integer.parseInt(sa[1]) - 1;
		}
		br.close();

		long[][][] d = new long[n][2][n];
		for (int i = 0; i < n; i++) {
			d[i] = dijkstra(i);
		}

		PrintWriter pw = new PrintWriter(System.out);
		for (int i = 0; i < q; i++) {
			if (d[s[i]][0][t[i]] == Long.MAX_VALUE) {
				pw.println(-1);
			} else {
				pw.println(d[s[i]][0][t[i]]);
			}
		}
		pw.flush();
	}

	static long[][] dijkstra(int s) {
		long[][] d = new long[2][list.size()];
		Arrays.fill(d[0], Long.MAX_VALUE);
		Arrays.fill(d[1], Long.MAX_VALUE);
		d[0][s] = 0;
		d[1][s] = 0;
		PriorityQueue<Node> que = new PriorityQueue<Node>();
		Node first = new Node(s, 0, 0);
		que.add(first);
		boolean[] fix = new boolean[n];
		while (!que.isEmpty()) {
			Node cur = que.poll();
			if (!fix[cur.v]) {
				fix[cur.v] = true;
				for (Hen hen : list.get(cur.v)) {
					long alt0 = d[0][cur.v];
					long alt1 = d[1][cur.v] + hen.c;
					if (alt1 > l) {
						alt0++;
						alt1 = hen.c;
					}
					if (alt0 < d[0][hen.v] ||
							alt0 == d[0][hen.v] && alt1 < d[1][hen.v]) {
						d[0][hen.v] = alt0;
						d[1][hen.v] = alt1;
						Node next = new Node(hen.v, alt0, alt1);
						que.add(next);
					}
				}
			}
		}
		return d;
	}

	static class Hen {
		int v, c;

		public Hen(int v, int c) {
			this.v = v;
			this.c = c;
		}
	}

	static class Node implements Comparable<Node> {
		int v;
		long h;
		long d;

		public Node(int v, long h, long d) {
			this.v = v;
			this.h = h;
			this.d = d;
		}

		public int compareTo(Node o) {
			if (h != o.h) {
				return Long.compare(h, o.h);
			}
			return Long.compare(d, o.d);
		}
	}
}

