	void solver(int N, int M, int[] u, int[] v, ArrayList<Integer>[] g) {
		DJSet ds = new DJSet(N);
		for (int i = 0; i < M; ++i) {
			ds.setUniont(u[i], v[i]);
		}
		boolean[] vis = new boolean[N];
		long[] cnt = new long[3];
		long sz = 0;
		for (int i = 0; i < N; ++i) {
			if (vis[ds.root(i)])
				continue;
			int t = type(ds.root(i), g);
			vis[ds.root(i)] = true;
			++cnt[t];
			if (t != 0)
				sz += ds.size(i);
		}
		long ans = 0;
		ans += cnt[0] * sz;
		ans += sz * cnt[0];
		ans += cnt[0] * cnt[0];
		ans += cnt[1] * cnt[1] * 2;
		ans += cnt[2] * cnt[2];
