	public static int dp(int i,int j) {
		if(i==0) return dp[i][j] = 1;
		if(dp[i][j] >= 0) return dp[i][j];
		dp[i][j]=0;
		for(int id : edges[j]) if((i & (1<<id)) != 0) dp[i][j]+= dp(i-(1<<id),id);
		return dp[i][j];
	}
}

