      dash.stp--;
      res.sub(dash);
      edge.setEle(res,from);
      if(edge.to(from).ele==null){
        Ele et=new Ele();
        et.add(edge.getEle(edge.to(from)));
        et.add(edge.getEle(from).pat,edge.getEle(from).stp-1);
        edge.to(from).ele=et;
      }
      return res;
    }
    Ele res=new Ele();
    Node to=edge.to(from);
    for(Edge next:to.edges){
      if(next==edge){
        continue;
      }
      res.add(calc(to,next));
    }
    res.stp++;
    edge.setEle(res,from);
    if(edge.both()){
      Ele ef=new Ele();
      ef.add(edge.elefrto);
      ef.add(edge.eletofr.pat,edge.eletofr.stp-1);
      Ele et=new Ele();
      et.add(edge.eletofr);
      et.add(edge.elefrto.pat,edge.elefrto.stp-1);
      edge.fr.ele=ef;
      edge.to.ele=et;
    }
    return res;
  }
  static class Node{
    List<Edge> edges;
    Ele ele;
    Node(){
      edges=new LinkedList<>();
    }
    void add(Edge e){
      edges.add(e);
    }
  }
  static class Edge{
    Node fr;
    Node to;
    Ele elefrto;
    Ele eletofr;
    Node to(Node from){
      if(from==fr){
        return to;
      }else if(from==to){
        return fr;
      }else{
        return null;
      }
    }
    Ele getEle(Node node){
      if(node==fr){
        return elefrto;
      }else if(node==to){
        return eletofr;
      }else{
        return null;
      }
    }
    void setEle(Ele ele,Node node){
      if(node==fr){
        elefrto=ele;
      }else if(node==to){
        eletofr=ele;
      }
    }
    boolean both(){
      return elefrto!=null&&eletofr!=null;
    }
    Edge(Node fr,Node to){
      this.fr=fr;
      this.to=to;
    }
  }
  static class Ele{
    long pat;
    int stp;
    Ele(){
      pat=1;
      stp=0;
    }
    Ele add(Ele o){
      return add(o.pat,o.stp);
    }
    Ele add(long p,int s){
      pat=(((pat*p)%mod*nck.nCk(stp+s,stp))%mod);
      stp+=s;
      return this;
    }
    Ele sub(Ele o){
      return sub(o.pat,o.stp);
    }
    Ele sub(long p,int s){
      pat=((pat*nck.inv(p))%mod*nck.inv(nck.nCk(stp,s))%mod);
      stp-=s;
      return this;
    }
    Ele copy(){
      Ele res=new Ele();
      res.pat=pat;
      res.stp=stp;
      return res;
    }
    public String toString(){
      return "["+pat+":"+stp+"]";
    }
  }
