class Solver {
    Reader in = new Reader ();
    Writer out = new Writer ();
    ArrayList <Integer> g[] = new ArrayList [100010];

    Pair farthest_node(int root, int n) {
        int [] dist = new int [n];
        Arrays.fill(dist, -1);

        Queue q = new Queue (n);
        q.push(root);
        dist[root] = 0;

        while(q.size() > 0) {
            int x = q.pop();
            for(int i : g[x]) {
                if(dist[i] == -1) {
                    dist[i] = 1 + dist[x];
                    q.push(i);
                }
            }
        }
        int farthest = 0;
        for(int i = 1; i < n; i++) {
            if(dist[farthest] < dist[i]) {
                farthest = i;
            }
        }
        return new Pair(dist[farthest], farthest);
    }
    void solve () {
        int n = in.nextInt();
        for(int i = 0; i < n; i++) {
            g[i] = new ArrayList <> ();
        }
        for(int i = 1; i < n; i++) {
            int p = in.nextInt() - 1;
            int q = in.nextInt() - 1;
            g[p].add(q);
            g[q].add(p);
        }
        Pair p = farthest_node(0, n);
        Pair q = farthest_node(p.second, n);
        int diameter = q.first;

        if(diameter % 3 == 1) {
            System.out.println("Second");
        } else {
            System.out.println("First");
        }
    }
}

