	static class DisjointSetUnion {
		public int[] parent;
		public int[] weight;
		public int count;

		public DisjointSetUnion(int nodes) {
			count = nodes;
			parent = new int[nodes];
			weight = new int[nodes];
			for (int i = 0; i < nodes; i++) {
				parent[i] = i;
				weight[i] = 1;
			}
		}
		//"find"
		public int root(int p) {
			while (p != parent[p]) {
				p = parent[p];
			}
			return p;
		}

		//"union"
		public void connect(int p, int q) {
			int rootP = root(p);
			int rootQ = root(q);
			if (rootP == rootQ) return;
			if (weight[rootP] < weight[rootQ]) {
				parent[rootP] = rootQ;
				weight[rootQ] += weight[rootP];
			} else {
				parent[rootQ] = rootP;
				weight[rootP] += weight[rootQ];
			}
			count--;
		}

		public boolean connected(int p, int q) {
			return root(p) == root(q);
		}
	}

	public void exec() throws Exception{
		final long M = 998244353L;
		final int N = sc.nextInt();
		final long[] U = new long[N];
		final long[] pattern = new long[N];
		for(int i=0;i<N;i++) {
			final int x = sc.nextInt();
			final int d = sc.nextInt();
			U[i] = pair(x, d);
		}
		final int[] set = new int[N];
		int tail = 0;
		Arrays.sort(U);
		set[tail++]=N-1;

		// 一番右は必ず末端なので2通りある。
		pattern[N-1] = 2;

		for(int i=N-2;i>=0;i--) {
			int head = 0;
			for(int s=0;s<tail;s++) {
				int rx = getPair1(U[set[s]]);
				int x  = getPair1(U[i]);
				int d  = getPair2(U[i]);
				if(rx < x+d) {
					// 巻き込み範囲である場合、現在のルートは更新する。
					if(pattern[i]==0) {
						pattern[i] = pattern[set[s]];
					}else {
						pattern[i] = pattern[i] * pattern[set[s]];
					}
					pattern[i] %= M;
				}else {
					set[head++]=set[s];
				}
			}
			// 現在探索の一番左は必ずルートになる。
			set[head++]=i;
			// 末端だった場合にはパターン数を設定。
			if(pattern[i]==0) {
				pattern[i] = 2;
			}else {
				pattern[i] = (pattern[i]+1) % M;
			}
			tail = head;
		}

//		err.println(Arrays.toString(root));
//		err.println(Arrays.toString(pattern));
//		err.println(Arrays.toString(Arrays.copyOf(set, tail)));
		long sum = pattern[set[0]];
		for(int i=1;i<tail;i++) {
			sum *= pattern[set[i]];
			sum %= M;
		}
		out.println(sum);
	}
}

