public class Main{
	static void solve(){//Here is the main function
		ArrayList<Integer> one = nextIntArray();
		int N = one.get(0);
		int K = one.get(1);
		int mod = 998244353;
		long[] dp = new long[N];
		long[] ruiseki = new long[N];
		dp[0] = 1;
		ruiseki[0] = 1;
		ArrayList<Node> S = new ArrayList<>();
		for(int i = 0; i < K; i++){
			ArrayList<Integer> tmp = nextIntArray();
			S.add(new Node(tmp.get(0), tmp.get(1)));
		}
		for(int i = 1; i < N; i++){
			for(int j = 0; j < S.size(); j++){
				Node check = S.get(j);
				if(i - check.L < 0){
					continue;
				}
				if(check.L == check.R){
					dp[i] += dp[i - check.L];
				}else if(i - check.R - 1 < 0){
					dp[i] += ruiseki[i - check.L];
				}else{
					dp[i] += ruiseki[i - check.L] - ruiseki[i - check.R - 1];
				}
				if(dp[i] < 0){
					dp[i] += mod;
				}
				dp[i] %= mod;
			}
			ruiseki[i] = dp[i] + ruiseki[i - 1];
			ruiseki[i] %= mod;
		}

		myout(dp[N - 1]);

	}
