import java.util.ArrayDeque;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Scanner;

public class Main {

	static final int INF_COIN = 100000001;
	static final long INF_DIST = 5000000000000000000L;

	public static void main(String[] args) {


		Scanner sc = new Scanner(System.in);
		String[] firstArr = sc.nextLine().split(" ");
		int n = Integer.parseInt(firstArr[0]);
		int m = Integer.parseInt(firstArr[1]);
		int p = Integer.parseInt(firstArr[2]);

		int[][] edgeArr = new int[n][n];
		for(int i = 0; i < n; i++) {
			for(int j = 0; j < n;j++) {
				edgeArr[i][j] = INF_COIN;
			}
		}
		for(int i = 0; i < m; i++) {
			String[] edgeStrArr = sc.nextLine().split(" ");
			int a = Integer.parseInt(edgeStrArr[0]);
			int b = Integer.parseInt(edgeStrArr[1]);
			int coin = (-1)* (Integer.parseInt(edgeStrArr[2]) - p);
			if(edgeArr[a-1][b-1] > coin) {
				edgeArr[a-1][b-1] = coin;
			}
		}

		sc.close();

		// 1から到達できない点を見つける
		int[] arriveArr = new int[n];
		ArrayDeque<Integer> queueArrive = new ArrayDeque<>();
		queueArrive.push(new Integer(0));
		arriveArr[0] = 1;
		while(!queueArrive.isEmpty()) {
			int nodeNo = queueArrive.pop();
			int[] nowEdgeArr = edgeArr[nodeNo];
			for(int i = 0; i < n; i++) {
				if(nowEdgeArr[i] < INF_COIN) {
					if(arriveArr[i] == 0) {
						queueArrive.push(new Integer(i));
						arriveArr[i] = 1;
					}
				}
			}
		}
		// ゴールにたどり着けない点を見つける
		int[] reachableArr = new int[n];
		ArrayDeque<Integer> queueReachable = new ArrayDeque<>();
		queueReachable.push(new Integer(n - 1));
		reachableArr[n - 1] = 1;
		while(!queueReachable.isEmpty()) {
			int endNodeNo = queueReachable.pop();
			for(int i = 0; i < n; i++) {
				if(edgeArr[i][endNodeNo] < INF_COIN) {
					if(reachableArr[i] == 0) {
						queueReachable.push(new Integer(i));
						reachableArr[i] = 1;
					}
				}
			}
		}

//		for(int i = 0; i < n; i++) {
//			System.out.println(Arrays.toString(edgeArr[i]));
//		}


		ArrayList<ArrayList<Integer>> edgeMtr = new ArrayList<>();
		for(int i = 0; i < n; i++) {
			ArrayList<Integer> edgeList = new ArrayList<>();
			edgeMtr.add(edgeList);
			if(arriveArr[i] == 0 || reachableArr[i] == 0) {
				continue;
			}
			for(int j = 0; j < n; j++) {
				if(edgeArr[i][j] >= INF_COIN || arriveArr[j] == 0 || reachableArr[j] == 0) {
					continue;
				}
				edgeList.add(j);
			}
		}

//		for(ArrayList<Integer> edgeList : edgeMtr) {
//			System.out.println(edgeList);
//		}

		long[] distArr = new long[n];
		for(int i = 0; i < n; i++) {
			distArr[i] = INF_DIST;
		}
		distArr[0] = 0;
		for(int i  = 0; i < n; i++) {
			for(int k = 0 ; k < n;k++) {
				ArrayList<Integer> edgeList = edgeMtr.get(k);
				for(int j = 0; j < edgeList.size();j++) {
					int endNode = edgeList.get(j);
					int edge = edgeArr[k][endNode];
					if(distArr[k] != INF_DIST && distArr[endNode] > distArr[k] + (long)edge){
						if(i == n - 1) {
							System.out.println(-1);
							return;
						}
						distArr[endNode] = distArr[k] + (long)edge;
					}
				}	
			}
		}

//		System.out.println(Arrays.toString(distArr));

		long maxCoin = distArr[n - 1] * (-1L);
		if(maxCoin < 0) {
			System.out.println(0);
		}else {
			System.out.println(maxCoin);
		}
	}
}

import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.util.*;

public class Main {

	class Node implements Comparable<Node>{
		int left, right;

		public Node(int left, int right) {
			this.left  = left;
			this.right = right;
		}

		@Override
		public int compareTo(Node o) {
			return right - o.right;
		}
	}

	public Main() {
		PrintWriter PW = new PrintWriter(System.out);
		FastScanner scanner = new FastScanner();
		int H = scanner.nextInt();
		int W = scanner.nextInt();

		TreeSet<Node>             nodeSet  = new TreeSet<>();
		TreeMap<Integer, Integer> costMap  = new TreeMap<>();

		for (int i = 1; i <= W; i++) {
			nodeSet.add(new Node(i, i));
		}
		costMap.put(0, W);

		Node A = new Node(0,0);
		Node B = new Node(0,0);
		for (int h = 1; h <= H; h++) {
			A.right = scanner.nextInt();
			B.right = scanner.nextInt() + 1;

			SortedSet<Node> sub = nodeSet.subSet(A, B);

			if (!sub.isEmpty()) {

				for (Node node : sub){
					int cost = node.right - node.left;
					int num  = costMap.get(cost);
					if (num != 1) {
						costMap.put(cost, num - 1);
					} else {
						costMap.remove(cost);
					}
				}

				Node node = sub.last();
				sub.clear();

				if (B.right != W+1) {
					node.right = B.right;
					if ( nodeSet.add(node) ) {
						int cost = node.right - node.left;
						costMap.put(cost, costMap.getOrDefault(cost,0)+1);
					}
				}

			}

			if (costMap.isEmpty()) {
				PW.println(-1);
			} else {
				PW.println(costMap.firstKey() + h);
			}
		}

		PW.close();
	}

	public static void main(String[] args) {
		new Main();
	}
}

class FastScanner {
	private final InputStream in = System.in;
	private final byte[] buffer = new byte[1024];
	private int ptr = 0;
	private int buflen = 0;

	private boolean hasNextByte() {
		if (ptr < buflen) {
			return true;
		} else {
			ptr = 0;
			try {
				buflen = in.read(buffer);
			} catch (IOException e) {
				e.printStackTrace();
			}
			if (buflen <= 0) {
				return false;
			}
		}
		return true;
	}

	private int readByte() {
		if (hasNextByte()) return buffer[ptr++];
		else return -1;
	}

	private static boolean isPrintableChar(int c) {
		return 33 <= c && c <= 126;
	}

	public boolean hasNext() {
		while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
		return hasNextByte();
	}

	public String next() {
		if (!hasNext()) throw new NoSuchElementException();
		StringBuilder sb = new StringBuilder();
		int b = readByte();
		while (isPrintableChar(b)) {
			sb.appendCodePoint(b);
			b = readByte();
		}
		return sb.toString();
	}

	public long nextLong() {
		if (!hasNext()) throw new NoSuchElementException();
		long n = 0;
		boolean minus = false;
		int b = readByte();
		if (b == '-') {
			minus = true;
			b = readByte();
		}
		if (b < '0' || '9' < b) {
			throw new NumberFormatException();
		}
		while (true) {
			if ('0' <= b && b <= '9') {
				n *= 10;
				n += b - '0';
			} else if (b == -1 || !isPrintableChar(b)) {
				return minus ? -n : n;
			} else {
				throw new NumberFormatException();
			}
			b = readByte();
		}
	}

	public int nextInt() {
		long nl = nextLong();
		if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE) throw new NumberFormatException();
		return (int) nl;
	}

	public double nextDouble() {
		return Double.parseDouble(next());
	}
}

