		long sz = 0;
		int[] color = new int[N];
		Arrays.fill(color, -1);
		for (int i = 0; i < N; ++i) {
			if (vis[ds.root(i)])
				continue;
			int t = type(ds.root(i), g, color);
			vis[ds.root(i)] = true;
			++cnt[t];
			if (t != 0)
				sz += ds.size(i);
		}
		long ans = 0;
		ans += cnt[0] * sz;
		ans += sz * cnt[0];
		ans += cnt[0] * cnt[0];
