		final long M = 998244353L;
		final int N = sc.nextInt();
		final long[] U = new long[N];
		final long[] pattern = new long[N];
		int D = 0;
		for(int i=0;i<N;i++) {
			final int x = sc.nextInt();
			final int d = sc.nextInt();
			U[i] = pair(x, d);
			D = Math.max(D, d);
		}
		final IntList set = new IntList(N);
		final IntList fix = new IntList(N);
		Arrays.sort(U);
		set.add(N-1);

		// 一番右は必ず末端なので2通りある。
		pattern[N-1] = 2;

		for(int i=N-2;i>=0;i--) {
			final int size = set.size();
			set.reset();
			for(int s=0;s<size;s++) {
				int rx = getPair1(U[set.get(s)]);
				int x  = getPair1(U[i]);
				int d  = getPair2(U[i]);
				if(rx < x+d) {
					// 巻き込み範囲である場合、現在のルートは更新する。
					if(pattern[i]==0) {
						pattern[i] = pattern[set.get(s)];
					}else {
						pattern[i] = pattern[i] * pattern[set.get(s)];
					}
					pattern[i] %= M;
				}else if(x + D < rx){
					// 最大移動距離よりも離れた場合は、それ以上連携されないのでfixに移動する。
					fix.add(set.get(s));
				}else {
					// まだ左からアクセスが可能な場合があるので、再度探索対象にする。
					set.add(set.get(s));
				}
			}
			// 現在探索の一番左は必ずルートになる。
			set.add(i);
			// 末端だった場合にはパターン数を設定。
			if(pattern[i]==0) {
				pattern[i] = 2;
			}else {
				pattern[i] = (pattern[i]+1) % M;
			}
		}

